import React from "react";
import { useNavigate } from "react-router-dom";

function Navbar() {
  const navigate = useNavigate();
  const role = localStorage.getItem("role");
  const isAdmin = role === "ADMIN";

  const handleLogout = () => {
    localStorage.clear();
    navigate("/");
  };

  return (
    <nav style={styles.nav}>
      <div style={styles.logoSection}>
        <h2 style={styles.logo}>Zoo Management System</h2>
      </div>

      <div style={styles.links}>
        <button style={styles.linkBtn} onClick={() => navigate("/home")}>
          Home
        </button>

        <button style={styles.linkBtn} onClick={() => navigate("/animals")}>
          Animals
        </button>

        <button style={styles.linkBtn} onClick={() => navigate("/enclosures")}>
          Enclosures
        </button>

        <button style={styles.linkBtn} onClick={() => navigate("/staff")}>
          Staff
        </button>

        <button
          style={styles.linkBtn}
          onClick={() => navigate("/feeding-schedules")}
        >
          Feeding
        </button>

        <button
          style={styles.linkBtn}
          onClick={() => navigate("/medical-records")}
        >
          Medical
        </button>

        {isAdmin && (
          <>
            <button style={styles.linkBtn} onClick={() => navigate("/admin")}>
              Admin
            </button>

            <button style={styles.linkBtn} onClick={() => navigate("/users")}>
              Users
            </button>
          </>
        )}

        <button style={styles.logoutBtn} onClick={handleLogout}>
          Logout
        </button>
      </div>
    </nav>
  );
}

const styles = {
  nav: {
    display: "flex",
    justifyContent: "space-between",
    alignItems: "center",
    padding: "18px 35px",
    background: "linear-gradient(90deg, #0f172a, #1e293b)",
    color: "#fff",
    flexWrap: "wrap",
    gap: "15px",
    boxShadow: "0 4px 18px rgba(0,0,0,0.2)",
  },
  logoSection: {
    display: "flex",
    alignItems: "center",
  },
  logo: {
    margin: 0,
    fontSize: "1.5rem",
    fontWeight: "bold",
    letterSpacing: "0.5px",
  },
  links: {
    display: "flex",
    gap: "10px",
    flexWrap: "wrap",
  },
  linkBtn: {
    background: "rgba(255,255,255,0.08)",
    color: "#fff",
    border: "1px solid rgba(255,255,255,0.15)",
    padding: "9px 14px",
    borderRadius: "8px",
    cursor: "pointer",
    fontWeight: "500",
  },
  logoutBtn: {
    background: "#dc2626",
    color: "#fff",
    border: "none",
    padding: "9px 14px",
    borderRadius: "8px",
    cursor: "pointer",
    fontWeight: "bold",
  },
};

export default Navbar;
